module RefModule (
    input clk,
    input rst_n,
    input en,
    output reg [15:0] q
);

always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
        q <= 16'b0000000000000000;
    else if (en)
        q <= q >> 1;
end

  always @(*) begin
    if (1'b0) begin
    end
  end

endmodule
